g_pQuestManager:AddQuestTemplet_LUA
{
    m_iID = 8950,
    m_eQuestType = QUEST_TYPE["QT_NORMAL"],
    CHANGE_JOB_TYPE = CHANGE_JOB_TYPE["CJT_JOB_NONE"],
    m_eStartNPCID = NPC_UNIT_ID["NUI_BILLBOARD"],
