    m_eRepeatType = QUEST_REPEAT_TYPE["QRT_DAY"],
    m_wstrMainText = "\"CoBo Abenteureraufruf\"\nDas seltsame Verhalten der Echsenmenschen, die in den Bergen Besmas leben, ist auf den finsteren Plan des Schattenschamanen Kaya zurückzuführen! Nun, da er besiegt und vertrieben wurde, ist er in die Unterwelt des Drachennests geflohen, um dort weiter dunkle Pläne zu schmieden: Er versucht, die alten Drachen wieder zu erwecken! Alle Abenteurer, die sich ihm stellen, um für den Frieden in Besma zu kämpfen, werden von CoBo reich belohnt werden!",
    m_wstrThanksText = "Gute Arbeit! Der nächste Aufruf wird um 6 Uhr gestartet. Ich kann doch wieder auf dich zählen, oder?",
    m_wstrDissClearText = "Um den Dungeon betreten zu können, brauchst du die Hilfe des Alchemisten Chachabuk aus Besma.",
